+        } else {
+            new_capacity = (*string_capacity)*2;
+        }
+
+        *ptr = realloc(*ptr, new_capacity);
+        ASSERT_MSG(*ptr != NULL, "%s", "pointer reallocation failed!");
+
+        *string_capacity = new_capacity;
+    }
+    *current_size = new_size - null_terminated_char_len;
+}
